mapper.insert:

    SELECT SEQ_INV_TX.NEXTVAL FROM DUAL

INSERT INTO INVENTORY_TRANSACTIONS (
      INVENTORY_TRANSACTION_ID
    , TRANSACTION_TYPE
    , REASON
    , TRANSACTION_MEMO
    , CREATED_BY
    , STORE_ID
    , RECEIPT_ID
    , STORE_CLOSING_ID
) VALUES (
      #{inventoryTransactionId}
    , #{transactionType}
    , #{reason}
    , #{transactionMemo}
    , #{createdBy}
    , #{storeId}
    , #{receiptId}
    , #{storeClosingId}
)

INSERT INTO INVENTORY_TRANSACTION_ITEMS (
      INVENTORY_TRANSACTION_ITEM_ID
    , BEFORE_QUANTITY
    , AFTER_QUANTITY
    , INVENTORY_TRANSACTION_ID
    , STORE_INVENTORY_ID
) VALUES

(
      SEQ_INV_TX_ITEM.NEXTVAL
    , #{item.beforeQuantity}
    , #{item.afterQuantity}
    , #{inventoryTransactionId}
    , #{item.storeInventoryId}
)

mapper.select:
SELECT INVENTORY_TRANSACTION_ID , CASE WHEN TRANSACTION_TYPE = 'RECEIPT' THEN '입고' WHEN TRANSACTION_TYPE = 'STORE_CLOSING' THEN '마감' WHEN TRANSACTION_TYPE = 'ADJUSTMENT' THEN '조정' END AS TRANSACTION_TYPE , REASON , CREATED_AT , CREATED_BY , CREATED_BY_NAME , STORE_NAME , STORE_ID FROM ( SELECT * FROM ( SELECT ROWNUM AS rn, temp.* FROM ( SELECT INVENTORY_TRANSACTION_ID , T.TRANSACTION_TYPE , T.REASON , T.CREATED_AT , T.CREATED_BY , U.USER_NAME AS CREATED_BY_NAME , S.STORE_NAME , STORE_ID FROM INVENTORY_TRANSACTIONS T JOIN USERS U ON ( T.CREATED_BY = U.USER_NO ) JOIN STORES S USING ( STORE_ID )
STORE_ID = #{condition.storeId}
AND TRANSACTION_TYPE = #{condition.transactionType}
ORDER BY T.CREATED_AT DESC, T.INVENTORY_TRANSACTION_ID ) temp WHERE ROWNUM <= #{paging.endRow} ) WHERE rn >= #{paging.startRow} )

SELECT COUNT(*) FROM INVENTORY_TRANSACTIONS T JOIN USERS U ON ( T.CREATED_BY = U.USER_NO ) JOIN STORES S USING ( STORE_ID )
STORE_ID = #{condition.storeId}
AND TRANSACTION_TYPE = #{condition.transactionType}
